<!DOCTYPE html>
<html>
<head>
    <style>
        body { font-family: sans-serif; display: flex; flex-direction: column; align-items: center; padding: 20px; }
        #maze { 
            border: 1px solid #000; 
            background: #fff;
        }
        .bot {
            position: absolute;
            width: 8px; height: 8px;
            border-radius: 50%;
            pointer-events: none;
            transition: transform 0.2s linear;
            will-change: transform;
        }
        #controls { margin-top: 10px; display: flex; gap: 20px; align-items: center; }
        #timer, #completed { font-size: 18px; font-weight: bold; }
        button { padding: 5px 15px; font-size: 16px; cursor: pointer; }
    </style>
</head>
<body>
    <div id="maze"></div>
    <div id="controls">
        <div id="timer">0</div>
        <div id="completed">0/24</div>
        <button id="reset">Reset</button>
    </div>

    <script>
        // Seeded RNG (LCG)
        function createRNG(seed) {
            let state = seed >>> 0;
            return function() {
                state = (state * 1664525 + 1013904223) >>> 0;
                return state / 4294967296;
            };
        }

        // Maze generation using DFS
        function generateMaze(rows, cols, rng) {
            const maze = [];
            for (let r = 0; r < rows; r++) {
                const row = [];
                for (let c = 0; c < cols; c++) {
                    row.push({n: true, e: true, s: true, w: true});
                }
                maze.push(row);
            }

            const visited = Array(rows).fill().map(() => Array(cols).fill(false));
            const stack = [];

            let r = 0, c = 0;
            visited[r][c] = true;

            while (true) {
                const neighbors = [];
                if (r > 0 && !visited[r-1][c]) {
                    neighbors.push({nr: r-1, nc: c, wall: 'n', otherWall: 's'});
                }
                if (c < cols-1 && !visited[r][c+1]) {
                    neighbors.push({nr: r, nc: c+1, wall: 'e', otherWall: 'w'});
                }
                if (r < rows-1 && !visited[r+1][c]) {
                    neighbors.push({nr: r+1, nc: c, wall: 's', otherWall: 'n'});
                }
                if (c > 0 && !visited[r][c-1]) {
                    neighbors.push({nr: r, nc: c-1, wall: 'w', otherWall: 'e'});
                }

                if (neighbors.length > 0) {
                    const idx = Math.floor(rng() * neighbors.length);
                    const chosen = neighbors[idx];

                    maze[r][c][chosen.wall] = false;
                    maze[chosen.nr][chosen.nc][chosen.otherWall] = false;

                    stack.push({r, c});
                    r = chosen.nr;
                    c = chosen.nc;
                    visited[r][c] = true;
                } else if (stack.length > 0) {
                    const prev = stack.pop();
                    r = prev.r;
                    c = prev.c;
                } else {
                    break;
                }
            }

            return maze;
        }

        // Bot class implementing Tremaux/DFS exploration
        class Bot {
            constructor(id, seed, spawn) {
                this.id = id;
                this.seed = seed;
                this.r = spawn.r;
                this.c = spawn.c;
                this.path = [{r: spawn.r, c: spawn.c}];
                this.deadEnds = new Set(); // cells marked as dead ends (subset of path)
                this.finishTick = null;

                // Memory structures
                this.exploredDirections = {}; // "r,c" -> {n:false, e:false, s:false, w:false}
                this.passageCounts = new Map(); // key "r1,c1,r2,c2" -> count (0-2)

                // Direction preference order based on seed
                const dirs = ['n', 'e', 's', 'w'];
                this.directionOrder = this.shuffle(dirs, seed);
            }

            shuffle(arr, seed) {
                const rng = createRNG(seed);
                for (let i = arr.length - 1; i > 0; i--) {
                    const j = Math.floor(rng() * (i + 1));
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                }
                return arr;
            }

            getDirection(from, to) {
                if (from.r < to.r) return 's';
                if (from.r > to.r) return 'n';
                if (from.c < to.c) return 'e';
                if (from.c > to.c) return 'w';
                return null;
            }

            passageKey(a, b) {
                const r1 = Math.min(a.r, b.r);
                const c1 = Math.min(a.c, b.c);
                const r2 = Math.max(a.r, b.r);
                const c2 = Math.max(a.c, b.c);
                return `${r1},${c1},${r2},${c2}`;
            }

            isVisited(cell) {
                // Any cell in path has been visited
                for (const p of this.path) {
                    if (p.r === cell.r && p.c === cell.c) return true;
                }
                return false;
            }

            move(game) {
                if (this.finishTick !== null) return;

                const current = {r: this.r, c: this.c};

                // Check if at exit
                if (game.isExit(current)) {
                    this.finishTick = game.elapsed;
                    return;
                }

                // Get reachable neighbors with direction
                const neighbors = [];
                const dirs = [
                    {dr: -1, dc: 0, dir: 'n', wall: 'n'},
                    {dr: 0, dc: 1, dir: 'e', wall: 'e'},
                    {dr: 1, dc: 0, dir: 's', wall: 's'},
                    {dr: 0, dc: -1, dir: 'w', wall: 'w'}
                ];

                for (const d of dirs) {
                    const nr = current.r + d.dr;
                    const nc = current.c + d.dc;
                    if (nr >= 0 && nr < game.rows && nc >= 0 && nc < game.cols) {
                        if (!game.hasWall(current.r, current.c, d.wall)) {
                            neighbors.push({r: nr, c: nc, dir: d.dir});
                        }
                    }
                }

                const cellKey = `${current.r},${current.c}`;
                if (!this.exploredDirections[cellKey]) {
                    this.exploredDirections[cellKey] = {n: false, e: false, s: false, w: false};
                }

                // Find unvisited neighbors that haven't been explored from current cell
                const unvisited = neighbors.filter(n => {
                    if (this.isVisited(n)) return false;
                    const dirKey = n.dir;
                    return !this.exploredDirections[cellKey][dirKey];
                });

                if (unvisited.length > 0) {
                    // Sort by direction preference order
                    unvisited.sort((a, b) => {
                        const idxA = this.directionOrder.indexOf(a.dir);
                        const idxB = this.directionOrder.indexOf(b.dir);
                        return idxA - idxB;
                    });

                    const chosen = unvisited[0];

                    // Mark direction as explored
                    this.exploredDirections[cellKey][chosen.dir] = true;

                    // Move to neighbor
                    this.moveTo(chosen, game);
                    return;
                }

                // Check if all directions from current cell have been explored
                const allDirs = ['n', 'e', 's', 'w'];
                const allExplored = allDirs.every(dir => this.exploredDirections[cellKey][dir]);

                if (allExplored) {
                    // Mark as dead end
                    this.deadEnds.add(cellKey);

                    // Backtrack to previous cell in path
                    if (this.path.length >= 2) {
                        const prev = this.path[this.path.length - 2];
                        const dir = this.getDirection(current, prev);
                        if (dir) {
                            this.moveTo(prev, game);
                            return;
                        }
                    }

                    // No way to backtrack? Stay put.
                    return;
                }

                // Find backtrackable neighbors (visited and passage count < 2)
                const backtrackable = neighbors.filter(n => {
                    if (this.isVisited(n)) {
                        const key = this.passageKey(current, n);
                        return this.passageCounts.get(key) < 2;
                    }
                    return false;
                });

                if (backtrackable.length > 0) {
                    // Prefer the previous cell in path if available
                    const prev = this.path[this.path.length - 2];
                    const prevCandidate = backtrackable.find(n => n.r === prev.r && n.c === prev.c);

                    let chosen;
                    if (prevCandidate) {
                        chosen = prevCandidate;
                    } else {
                        // Sort by direction preference and pick first
                        backtrackable.sort((a, b) => {
                            const idxA = this.directionOrder.indexOf(a.dir);
                            const idxB = this.directionOrder.indexOf(b.dir);
                            return idxA - idxB;
                        });
                        chosen = backtrackable[0];
                    }

                    this.moveTo(chosen, game);
                    return;
                }

                // No way forward or backtrack. Shouldn't happen in perfect maze.
                this.deadEnds.add(cellKey);
            }

            moveTo(target, game) {
                const from = {r: this.r, c: this.c};
                const to = target;

                // Update passage count (undirected edge)
                const key = this.passageKey(from, to);
                const currentCount = this.passageCounts.get(key) || 0;
                this.passageCounts.set(key, currentCount + 1);

                // Update position
                this.r = to.r;
                this.c = to.c;

                // Add to path
                this.path.push({r: to.r, c: to.c});
            }
        }

        // Game class
        class Game {
            constructor() {
                this.rows = 15;
                this.cols = 15;
                this.spawn = {r: 0, c: 0};
                this.exit = null;
                this.maze = [];
                this.bots = [];
                this.elapsed = 0;
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');
                this.cellSize = 20;

                // Visual bots
                this.botElements = [];

                // Animation loop
                this.running = false;

                this.init();
            }

            init() {
                this.canvas.width = 400;
                this.canvas.height = 400;
                this.cellSize = Math.floor(Math.min(this.canvas.width / this.cols, this.canvas.height / this.rows));

                // Create bot elements
                for (let i = 0; i < 24; i++) {
                    const el = document.createElement('div');
                    el.className = 'bot';
                    // Distinct colors using HSL
                    el.style.backgroundColor = `hsl(${i * 15}, 70%, 50%)`;
                    this.canvas.appendChild(el);
                    this.botElements.push(el);
                }

                this.running = true;
                requestAnimationFrame(this.animate.bind(this));
            }

            reset(seed = Math.random()) {
                const rng = createRNG(seed);

                // Generate maze
                this.maze = generateMaze(this.rows, this.cols, rng);

                // Choose exit deterministically based on seed
                let er, ec;
                do {
                    er = Math.floor(rng() * this.rows);
                    ec = Math.floor(rng() * this.cols);
                } while (er === this.spawn.r && ec === this.spawn.c);
                this.exit = {r: er, c: ec};

                // Create bots with different seeds for direction preference
                this.bots = [];
                for (let i = 0; i < 24; i++) {
                    const botSeed = rng() * 1000;
                    this.bots.push(new Bot(i, botSeed, this.spawn));
                }

                this.elapsed = 0;

                // Reset visual bots positions
                for (let i = 0; i < this.bots.length; i++) {
                    const bot = this.bots[i];
                    const el = this.botElements[i];
                    this.updateBotVisual(bot, el);
                }

                // Draw maze
                this.drawMaze();

                // Update UI
                document.getElementById('timer').textContent = '0';
                document.getElementById('completed').textContent = `0/24`;
            }

            hasWall(r, c, dir) {
                if (r < 0 || r >= this.rows || c < 0 || c >= this.cols) return true;
                return this.maze[r][c][dir];
            }

            isExit(cell) {
                return cell.r === this.exit.r && cell.c === this.exit.c;
            }

            drawMaze() {
                const ctx = this.ctx;
                ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

                ctx.strokeStyle = '#000';
                ctx.lineWidth = 1;

                for (let r = 0; r < this.rows; r++) {
                    for (let c = 0; c < this.cols; c++) {
                        const cell = this.maze[r][c];
                        const x = c * this.cellSize;
                        const y = r * this.cellSize;

                        ctx.beginPath();
                        if (cell.n) {
                            ctx.moveTo(x, y);
                            ctx.lineTo(x + this.cellSize, y);
                        }
                        if (cell.e) {
                            ctx.moveTo(x + this.cellSize, y);
                            ctx.lineTo(x + this.cellSize, y + this.cellSize);
                        }
                        if (cell.s) {
                            ctx.moveTo(x + this.cellSize, y + this.cellSize);
                            ctx.lineTo(x, y + this.cellSize);
                        }
                        if (cell.w) {
                            ctx.moveTo(x, y + this.cellSize);
                            ctx.lineTo(x, y);
                        }
                        ctx.stroke();
                    }
                }

                // Draw exit marker
                const ex = this.exit.c * this.cellSize;
                const ey = this.exit.r * this.cellSize;
                ctx.fillStyle = 'green';
                ctx.fillRect(ex + 2, ey + 2, this.cellSize - 4, this.cellSize - 4);
            }

            updateBotVisual(bot, el) {
                const x = bot.c * this.cellSize + this.cellSize / 2;
                const y = bot.r * this.cellSize + this.cellSize / 2;
                // Use translate for smooth movement
                el.style.transform = `translate(${x}px, ${y}px)`;
            }

            animate(timestamp) {
                if (!this.running) return;

                // Update bot visual positions based on logical state
                for (let i = 0; i < this.bots.length; i++) {
                    const bot = this.bots[i];
                    const el = this.botElements[i];
                    this.updateBotVisual(bot, el);
                }

                // Update UI
                document.getElementById('timer').textContent = this.elapsed;
                const completed = this.bots.filter(b => b.finishTick !== null).length;
                document.getElementById('completed').textContent = `${completed}/24`;

                requestAnimationFrame(this.animate.bind(this));
            }

            tick(n = 1) {
                for (let i = 0; i < n; i++) {
                    if (this.allBotsFinished()) {
                        break; // Don't advance elapsed further
                    }
                    this.advanceTick();
                }
            }

            allBotsFinished() {
                return this.bots.every(b => b.finishTick !== null);
            }

            advanceTick() {
                // Increment elapsed only if not all bots finished before this tick
                const allFinishedBefore = this.allBotsFinished();
                if (allFinishedBefore) return;

                this.elapsed++;

                // Process each bot's move in deterministic order
                for (const bot of this.bots) {
                    if (bot.finishTick === null) {
                        bot.move(this);
                    }
                }
            }
        }

        // Create global game instance
        window.game = new Game();

        // Reset button
        document.getElementById('reset').addEventListener('click', () => {
            window.game.reset();
        });
    </script>
</body>
</html>
